task.output_schema:

# {episode_id}-final-report.yaml
# Auto-generated by cost-report task (T3)

episode_id: "{episode_id}"
generated_at: "{ISO-8601 timestamp}"
estimate_source: "_cost/estimates/{episode_id}-estimate.yaml"
actuals_source: "_cost/actuals/{episode_id}-actuals.yaml"

summary:
  total_estimated: {float}
  total_actual: {float}
  total_variance: {float}
  total_variance_percent: "{signed float}%"
  budget_status: "{under_budget|on_budget|over_budget}"
  total_scenes: {int}
  total_api_calls: {int}
  total_retakes: {int}
  currency: "USD"

variance_by_tool:
  - tool: "{tool_name}"
    estimated_calls: {int}
    actual_calls: {int}
    estimated_cost: {float}
    actual_cost: {float}
    variance: {float}
    variance_percent: "{signed float}%"
    retake_count: {int}
    retake_cost: {float}

variance_by_scene:
  - scene_id: "{scene_id}"
    estimated_cost: {float}
    actual_cost: {float}
    variance: {float}
    variance_percent: "{signed float}%"
    status: "{under|on_budget|over}"
    retake_count: {int}
    retake_cost: {float}
    retake_reasons: ["{reason}", ...]

variance_by_phase:
  - phase: "{phase_name}"
    total_cost: {float}
    total_calls: {int}
    percentage_of_total: {float}

retake_history:
  total_retakes: {int}
  total_retake_cost: {float}
  retake_percentage_of_total: "{float}%"
  estimated_retake_buffer: {float}
  retake_buffer_used_percent: "{float}%"
  entries:
    - scene_id: "{scene_id}"
      tool: "{tool_name}"
      retake_reason: "{reason}"
      cost: {float}
      timestamp: "{ISO-8601}"

revision_costs:
  total_revisions: {int}
  total_revision_cost: {float}
  avg_revision_cost_per_scene: {float}
  by_scene:
    - scene_id: "{scene_id}"
      revision_count: {int}
      revision_cost: {float}

task.project_output_schema:

# PROJECT-{project_id}-report.yaml
# Auto-generated by cost-report task (T3) — project-level aggregation

project_id: "{project_id}"
generated_at: "{ISO-8601 timestamp}"
budget: {total_project_budget}
currency: "USD"

summary:
  total_spent: {float}
  remaining: {float}
  budget_utilization: "{float}%"
  budget_status: "{on_track|warning|halt}"
  total_episodes: {int}
  episodes_complete: {int}
  episodes_in_progress: {int}

per_episode:
  - episode_id: "{episode_id}"
    title: "{title}"
    status: "{status}"
    estimated: {float}
    actual: {float}
    variance: {float}
    variance_percent: "{signed float}%"

shared_costs:
  character_generation: {float}
  brand_assets: {float}
  environment_generation: {float}
  total_shared: {float}
  amortized_per_episode: {float}

breakdown_by_tool:
  - tool: "{tool_name}"
    estimated: {float}
    actual: {float}
    calls: {int}

budget_alerts:
  alert_at_percent: {int}
  halt_at_percent: {int}
  current_utilization: "{float}%"
  status: "{on_track|warning|halt}"
